import React from 'react';
import './Welcome.css'
import axios from 'axios';
import { useFormik } from 'formik';

function AddForm () {

    const formik = useFormik({
        initialValues: {
            id: '',
            date: '',
            status: ''
        },
        onSubmit: values => {
            alert(JSON.stringify(values, null, 2));
        }
    })

    // const postRequest = (userName) => 
    // {
    //     axios.post(`http://localhost:8080/users/${userName}/items`).then(response => console.log(response.userName))
    //    .catch(error => {console.log(error.data)})
    // } 
    return (
        <div className='location-form'>
            <form onSubmit={formik.handleSubmit}>
                <div>
                <label htmlFor='id'> Description </label>
                <input onChange={formik.handleChange} value = {formik.values.ID} type='text' id='Description' name = 'description'/>
                </div>
                <div>
                <label htmlFor='date'> Date </label>
                <input onChange={formik.handleChange} value = {formik.values.Date} type='text' id='Date' name = 'date'/>
                </div>

                <div>
                <label htmlFor='status'> Status </label>
                <input onChange={formik.handleChange} value = {formik.values.Status} type='text' id='Status' name = 'status'/>
                </div>

                <button>Submit</button>
            </form>
        </div>
    )
}

export default AddForm;
